  ('medical-tech-moex-20298', 'medical-tech', 'medical-tech-moex-093-4222900d', 'sub-medical-tech-12', NULL, 'single_choice', '要從有綠膿桿菌污染的痰檢體分離結核菌時，何種溶痰去污劑效果較佳？ trisodium phosphate (TSP)-zephiran  5% oxalic acid N-acetyl-L-cysteine加2% NaOH  dithiothreitol 加 2% NaOH', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:14+00:00", "source_pdf_sha1": "c2bd1634fb6a", "answer_pdf_sha1": "83395b9967fb", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學(包括細菌與黴菌)", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 57, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
