  ('medical-tech-moex-20301', 'medical-tech', 'medical-tech-moex-093-4222900d', 'sub-medical-tech-12', NULL, 'single_choice', '下列有關Penicillium marneffei之特性，何者不正確？ 可引起免疫不全患者之深部性黴菌病 接種Sabouraud dextrose agar室溫培養，可產生水溶性紅色色素 在宿主組織中以酵母菌型存在，並可見行出芽繁殖（budding） 室溫培養時具有快速生長之透明黴菌特徵', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:14+00:00", "source_pdf_sha1": "c2bd1634fb6a", "answer_pdf_sha1": "83395b9967fb", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學(包括細菌與黴菌)", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 60, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20302', 'medical-tech', 'medical-tech-moex-093-4222900d', 'sub-medical-tech-12', NULL, 'single_choice', '快速生長，菌落如棉花糖，鏡檢可見不分隔寬廣菌絲、圓形孢子囊、孢子囊柄（sporangiophore）正 下方有發達的假根（rhizoid），此菌應為下列何者？ Absidia  Mucor  Rhizopus  Rhizomucor', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:14+00:00", "source_pdf_sha1": "c2bd1634fb6a", "answer_pdf_sha1": "83395b9967fb", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學(包括細菌與黴菌)", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 61, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20303', 'medical-tech', 'medical-tech-moex-093-4222900d', 'sub-medical-tech-12', NULL, 'single_choice', 'nitrate reduction test加試劑後不變色，加鋅粉仍不變色，下列敘述何者不正確？ 此試驗結果為陰性 硝酸鹽已被還原為亞硝酸鹽以外的產物如氮氣 培養基中已無硝酸鹽 培養基中已無亞硝酸鹽', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:14+00:00", "source_pdf_sha1": "c2bd1634fb6a", "answer_pdf_sha1": "83395b9967fb", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學(包括細菌與黴菌)", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 62, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20304', 'medical-tech', 'medical-tech-moex-093-4222900d', 'sub-medical-tech-12', NULL, 'single_choice', '下列有關 indole test之敘述，何者正確？ 腸內菌之試驗通常使用Ehrlich’s indole reagent 葡萄糖非發酵菌之試驗通常使用Kovacs indole reagent 厭氧菌宜用p-dimethyl-aminocinnamaldehyde為試劑，陽性在30秒內呈藍色或藍綠 使用Kovacs indole reagent之前需先加xylene萃取indole', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:14+00:00", "source_pdf_sha1": "c2bd1634fb6a", "answer_pdf_sha1": "83395b9967fb", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學(包括細菌與黴菌)", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 63, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20305', 'medical-tech', 'medical-tech-moex-093-4222900d', 'sub-medical-tech-12', NULL, 'single_choice', '細菌要能快速發酵乳糖，必須具備下列那些酵素？ β-galactosidase   lactose permease β-lactamase   β-glucosidase', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:14+00:00", "source_pdf_sha1": "c2bd1634fb6a", "answer_pdf_sha1": "83395b9967fb", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學(包括細菌與黴菌)", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 64, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20306', 'medical-tech', 'medical-tech-moex-093-4222900d', 'sub-medical-tech-12', NULL, 'single_choice', '有關esculin水解試驗，下列何者代表陽性反應？ 菌落周圍培養基變棕黑色  菌落周圍培養基變黃色 菌落周圍培養基在長波UV燈下有鮮藍色螢光  菌落中心呈黑色', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:14+00:00", "source_pdf_sha1": "c2bd1634fb6a", "answer_pdf_sha1": "83395b9967fb", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學(包括細菌與黴菌)", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 65, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20307', 'medical-tech', 'medical-tech-moex-093-4222900d', 'sub-medical-tech-12', NULL, 'single_choice', '下列有關citrate agar之敘述，何項不正確？ 含bromthymol blue為酸鹼指示劑 含protein為氮源 只能接種微量接種原 陽性反應可使培養基變藍，或雖不變藍色，但可見明顯長菌現象', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:14+00:00", "source_pdf_sha1": "c2bd1634fb6a", "answer_pdf_sha1": "83395b9967fb", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學(包括細菌與黴菌)", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 66, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
